SELECT ?rec ?n WHERE {
  ?hurr a goo:HurricaneEventRecord ;
        rdfs:label ?hname ;
        goo:eventStartTime ?hstart ;
        goo:eventEndTime ?hend .
  FILTER(CONTAINS(STR(?hname), "Ian"))
  ?rec a goo:CustomerOutageRecord ;
       goo:representsCounty ?county ;
       goo:numberOfOutages ?n ;
       goo:recordDateTime ?dt .
  ?county goo:fipsCode "12071" .
  FILTER(?n > 100)
  FILTER(?dt >= ?hstart && ?dt <= ?hend)
}
ORDER BY DESC(?n)
LIMIT 10

