SELECT ?county (MAX(?n) AS ?maxOutages) WHERE {
  ?irma a goo:HurricaneEventRecord ;
        rdfs:label ?iname ;
        goo:eventStartTime ?istart .
  FILTER(CONTAINS(STR(?iname), "Irma"))
  ?rec a goo:CustomerOutageRecord ;
