PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX units: <http://www.opengis.net/def/uom/OGC/1.0/>

SELECT ?hname ?peakOutage WHERE {
  {
    SELECT (MAX(?n) AS ?peakOutage) WHERE {
      ?rec a goo:CustomerOutageRecord ;
           goo:representsCounty ?c ;
           goo:numberOfOutages ?n ;
           goo:recordDateTime ?d .
      ?c goo:fipsCode "12071" .
      FILTER(SUBSTR(STR(?d), 1, 10) = "2022-09-28")
    }
  }
  ?county a goo:County ;
          goo:fipsCode "12071" ;
          geosparql:hasGeometry ?cgeom .
  ?cgeom geosparql:asWKT ?cwkt .
  ?hurr a goo:HurricaneEventRecord ;
        rdfs:label ?hname ;
        goo:hasTrackRecord ?trk .
  ?trk goo:recordDateTime ?td ;
       goo:lat ?la ;
       goo:lon ?lo .
  FILTER(SUBSTR(STR(?td), 1, 10) = "2022-09-28")
  BIND(STRDT(CONCAT("POINT(", STR(?lo), " ", STR(?la), ")"), geosparql:wktLiteral) AS ?pt)
  FILTER(geof:distance(?cwkt, ?pt, units:metre) <= 100000)
}

