    SELECT ?state (COUNT(?e) AS ?count2020) WHERE {
      ?e a goo:StormEventRecord ;
         goo:occurredInState ?state ;
         goo:eventStartTime ?d .
      FILTER(YEAR(?d) = 2020)
    }
    GROUP BY ?state
