    SELECT ?state (COUNT(?e2) AS ?count2010) WHERE {
      ?e2 a goo:StormEventRecord ;
          goo:occurredInState ?state ;
          goo:eventStartTime ?d2 .
      FILTER(YEAR(?d2) = 2010)
    }
    GROUP BY ?state
  }
}
ORDER BY DESC(?difference)
